2351   MatrixTy VisitStore(StoreInst *Inst, const ShapeInfo &SI, Value *StoredVal,
2352                       Value *Ptr, IRBuilder<> &Builder) {
2353     return LowerStore(Inst, StoredVal, Ptr, Inst->getAlign(),
2354                       getIndex(Ptr, SI.getStride()), Inst->isVolatile(), SI,
2355                       Builder);
